clc
close all
clear all
format long
tic
lambdapump = 3000;           			    % pump wavelength [nm]
Aeff =3.9336411862798E-11;	  	% effective mode area [m^2]
power =1000;         		      	% peak power of input [W]
FWHM = 50e-3;                               % pulse width in FWHM [ps]
%%Dispersion Engineering
%%==============X===================================================================================================
N_betas = 10;                     	% number of higer order dispersion
N_pump = 6;                      	% index number of pumpwavelength
c = 3e-7; 		 	% Unit of velocity (c) of light is km/ps
del_lambda = 100*1e-12;
lambda = (1000*1e-12:del_lambda:8000*1e-12);
% Unit of 2wavelength (lambda) in km
N = length(lambda);
csv_path = fullfile(fileparts(mfilename('fullpath')), '..', 'Hang V', 'all n_hang.csv');
imported_data = importdata(csv_path);
if isstruct(imported_data)
    n_eff_data = imported_data.data;
else
    n_eff_data = imported_data;
end

D_all = zeros(N, 4);
for i = 1:4
    n_eff_col = n_eff_data(1:N, i);
    [betas_col, D_col] = dispersion(lambda, n_eff_col, N, del_lambda, N_pump);
    D_all(:, i) = D_col;
    if i == 4
        betas = betas_col;
        D = D_col;
    end
end
lambda=lambda*1e3;
betas=betas(1:N_betas);

figure(1)
clf;
plot_lambda = lambda(2:N-1) / 1e-6;
hold on;
plot(plot_lambda, D_all(2:N-1, 1), 'k-', 'linewidth', 2.5);
plot(plot_lambda, D_all(2:N-1, 2), 'r--', 'linewidth', 2.5);
plot(plot_lambda, D_all(2:N-1, 3), 'b-.', 'linewidth', 2.5);
plot(plot_lambda, D_all(2:N-1, 4), 'g--', 'linewidth', 2.5);

plot([0.5 8], [0 0], 'r--', 'linewidth', 1.5);
plot([1.5 1.5], [-800 250], 'r--', 'linewidth', 1.5);

xlabel('Wavelength [\mum]', 'FontSize', 20, 'FontWeight', 'bold');
ylabel('D [ps/nm/km]', 'FontSize', 20, 'FontWeight', 'bold');
xlim([0.5, 8]);
ylim([-800, 450]); % Increased upper limit to fit the legend at Y=400
set(gca, 'FontSize', 16, 'LineWidth', 1.5);
set(gca, 'XMinorTick', 'on', 'YMinorTick', 'on');
box on;
grid on;

lgd = legend('H = 0.05 \mum', 'H = 0.1 \mum', 'H = 0.15 \mum', 'H = 0.2 \mum', 'FontSize', 18, 'FontWeight', 'bold', 'FontAngle', 'italic');
legend('boxoff');

% Calculate normalized figure coordinates to place the legend at X=4.5, Y=400
drawnow; % Ensure the axes and legend are drawn to get correct positions
ax_pos = get(gca, 'Position');
xl = xlim; yl = ylim;
pos_x = (4.5 - xl(1)) / (xl(2) - xl(1));
pos_y = (400 - yl(1)) / (yl(2) - yl(1));
fig_x = ax_pos(1) + pos_x * ax_pos(3);
fig_y = ax_pos(2) + pos_y * ax_pos(4);

% Update legend position
lgd_pos = get(lgd, 'Position');
lgd_pos(1) = fig_x;
lgd_pos(2) = fig_y;
set(lgd, 'Position', lgd_pos);

text(2, 100, 'R = 5 \mum', 'FontSize', 18, 'FontWeight', 'bold', 'FontAngle', 'italic');
hold off;

%==============================================================================================================================================
% SC generation
%==============================================================================================================================================
% === simulatation parameters for supercontinuum generation
nt = 2^13;                   			    % number of grid points (FFT)
%dt = 2.76e-3;                              % time step [ps]
T = 20;                                     % Time window [ps]
dt = T/nt;                                 	% time step
%T = nt*dt;                                 % width of time window [ps]
c = 3e8*1e9/1e12;                           % speed of light [nm/ps]

f0 = c/lambdapump;                          % pump frequency [THz] [pump frequency = 193.55 THz at 1550 nm]
w0 = 2*pi*f0;                               % angular pump frequency
t = linspace(-T/2, T/2, nt); 				% time grid
V = 2*pi*(-nt/2:nt/2-1)'/(nt*dt);   		% frequency grid

%[W_length]=Waveguide_length();
%dlength = W_length(1);                 	% device length [m]
dlength = 10e-3;

n2 = 1.1e-17;                           % nonlinear refrective index [m^2/W] for GeAsSe

loss =65;                               % loss [dB/m]

%nonlinear refrective index [m^2/W] for SiC is 8.6e-19
%Loss for SiC 2.3*100
%nonlinear refrective index [m^2/W] for LiNbO3 is 9.33e-20
% Loss for liNbO3 0.2*100
%nonlinear refrective index [m^2/W] for Si3N4 is 2.5e-19
% Loss for Si3N4  6
%nonlinear refrective index [m^2/W] for CdTe is 9.5e-17
% Loss for CdTe  500
beta_TPA = 0; % [m/W] for Si at 3000 nm

gamma = 2*pi*n2/(1e-9*lambdapump*Aeff) + 1i*beta_TPA/(2*Aeff);	% nonlinear coefficient [1/W/m]

% === input pulse and parameters


chirp = 0;
mshape = 0;
T0 = FWHM/(2*acosh(sqrt(2)));

if mshape == 0
    A =sqrt(power)*sech(t/T0).*exp(-1i*chirp*t.^2/(2*T0.^2));	% input field [W^(1/2)]
else
    A =exp(-0.5*(1+1i*chirp).*(t/T0).^(2*mshape));
end

%
% %%% Noise
% W = V+w0;
% % hbar=6.636e-10/(2*pi);
% % f_req =10E6;
% % B=sqrt(hbar.*W/2*pi*f_req);
% B =2e-6;
% noise_strength = 0.0001;   
% phase_noise = noise_strength * 2 * pi .* (rand(1,8192));  % Now centered around 0
% c_noise = exp(1i * phase_noise);
% % Anoise=B'.*c_noise;
% Anoise=c_noise;
% % %Anoise=Anoise(1,:);
% A=A.*Anoise;


LD = T0^2/abs(betas(2));				% dispersion length [m]
LNL = 1/(gamma*power);					% non-linear length [m]
N = sqrt(LD/LNL);						% soliton order
Lfiss = (LD/N);							% soliton fission length [m]

% === Raman response
fr = 0.013;						 % fractional Raman contribution forGeAsSe
tau1 = 21.3;						% duration [ps]
tau2 = 195;
%fr = 0.148;
%tau1 = 23e-3;							% duration [ps] for As2se3
%tau2 = 164.5e-3;						% duration [ps]
%fr = 0.031;							% fractional Raman contribution for Chalcogenide As2s3
%tau1 = 15.5e-3;						% duration [ps]
%tau2 = 230.5e-3;						% duration [ps]
RT = ((tau1^2+tau2^2)/(tau1*tau2^2)).*sin(t/tau1).*exp(-t/tau2);
RT(t<0) = 0;							% heaviside step function
RT = RT/trapz(t,RT);  					% normalise RT to unit integral
Tr = 0;

% === simulation parameters
nplot = 240;							% number of length steps to save field at

%----propagation field
[Z, AT, AW, W] = gnlse(t, V, A, w0, gamma, betas, loss, fr, Tr, dlength,RT,nplot);

IA = abs(A).^2;
IAf = abs(fftshift(ifft(A)).*(nt*dt)/sqrt(2*pi)).^2;
mIAf = max(max(IAf));
lIAf = 10*log10(IAf/mIAf);



IW = abs(AW).^2; 						% spectral intensity
mIW = max(max(IW));        				% max value, for scaling plot
lIW = 10*log10(IW/mIW);

IT = abs(AT).^2; 						% temporal intensity
mIT = max(max(IT));       				% max value, for scaling plot
lIT = 10*log10(IT/mIT);

WL = 2*pi*c./W;							% wavelength grid
iis = (WL>300 & WL<20000);


% === spectrogram analysis
%alfa = 50e-3;		% pulsewidth for optical gating [ps]
%spf = spectrogram (alfa, t, AT, nt);


